describe("Quoting", () => {
  it.todo("should compute premium for a single sword (new customer, first policy)");
  it.todo("should compute premium for other main item types (amulet, staff, potion)");
  it.todo("should compute premium for a single component");
  it.todo("should sum premiums for multiple items");
  it.todo("should apply building block discount for 3 alike components");
  it.todo("should add 50% surcharge for cursed items");
