interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

interface QuoteResult {
  premium: number;
}

interface ScenarioOutput {
  results: QuoteResult[];
}

const COMPONENT_BASE_PREMIUM = 25;
const BUILDING_BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

function withSurcharge(base: number): number {
  return base + base / 10;
}

export function processScenario(scenario: Scenario): ScenarioOutput {
  const items = scenario.steps[0].items;
  let itemPremiumTotal = 0;

  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (BASE_PREMIUMS[item.type] !== undefined) {
      itemPremiumTotal += withSurcharge(BASE_PREMIUMS[item.type]);
    } else {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    }
  }

  for (const type in componentCounts) {
    const count = componentCounts[type];
    const blocks = Math.floor(count / 3);
    const remainder = count % 3;
    itemPremiumTotal += blocks * withSurcharge(BUILDING_BLOCK_PREMIUM);
    itemPremiumTotal += remainder * withSurcharge(COMPONENT_BASE_PREMIUM);
  }

  const premium = Math.ceil(itemPremiumTotal + 5);
  return { results: [{ premium }] };
}

