interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

interface QuoteResult {
  premium: number;
}

interface ScenarioOutput {
  results: QuoteResult[];
}

const COMPONENT_BASE_PREMIUM = 25;
const BUILDING_BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

function withFirstInsuranceSurcharge(base: number): number {
  return base + base / 10;
}

export function processScenario(scenario: Scenario): ScenarioOutput {
  const items = scenario.steps[0].items;
  let itemPremiumTotal = 0;

  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (BASE_PREMIUMS[item.type] !== undefined) {
      const basePremium = BASE_PREMIUMS[item.type];
      const cursedMultiplier = item.cursed ? 1.5 : 1;
      const enchantmentMultiplier = item.enchantment >= 5 ? 1.3 : 1;
      itemPremiumTotal += withFirstInsuranceSurcharge(basePremium * cursedMultiplier * enchantmentMultiplier);
    } else {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    }
  }

  for (const type in componentCounts) {
    const count = componentCounts[type];
    const blocks = Math.floor(count / 3);
    const remainder = count % 3;
    itemPremiumTotal += blocks * withFirstInsuranceSurcharge(BUILDING_BLOCK_PREMIUM);
    itemPremiumTotal += remainder * withFirstInsuranceSurcharge(COMPONENT_BASE_PREMIUM);
  }

  const loyaltyMultiplier = scenario.customer.yearsWithMHPCO >= 2 ? 0.8 : 1;
  itemPremiumTotal *= loyaltyMultiplier;

  const premium = Math.ceil(itemPremiumTotal + 5);
  return { results: [{ premium }] };
}

