interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

interface QuoteResult {
  premium: number;
}

interface ScenarioOutput {
  results: QuoteResult[];
}

const COMPONENT_BASE_PREMIUM = 25;
const BUILDING_BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

function applyContractModifier(base: number, isFirst: boolean): number {
  if (isFirst) return base + base / 10;
  return base * 0.85;
}

export function processScenario(scenario: Scenario): ScenarioOutput {
  const results: QuoteResult[] = [];
  let quoteCount = 0;

  for (const step of scenario.steps) {
    const items = step.items;
    const isFirstQuote = quoteCount === 0;
    quoteCount++;

    let itemPremiumTotal = 0;

    const componentCounts: Record<string, number> = {};
    for (const item of items) {
      if (BASE_PREMIUMS[item.type] !== undefined) {
        const basePremium = BASE_PREMIUMS[item.type];
        const cursedMultiplier = item.cursed ? 1.5 : 1;
        const enchantmentMultiplier = item.enchantment >= 5 ? 1.3 : 1;
        itemPremiumTotal += applyContractModifier(basePremium * cursedMultiplier * enchantmentMultiplier, isFirstQuote);
      } else {
        componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
      }
    }

    for (const type in componentCounts) {
      const count = componentCounts[type];
      const blocks = Math.floor(count / 3);
      const remainder = count % 3;
      itemPremiumTotal += blocks * applyContractModifier(BUILDING_BLOCK_PREMIUM, isFirstQuote);
      itemPremiumTotal += remainder * applyContractModifier(COMPONENT_BASE_PREMIUM, isFirstQuote);
    }

    const loyaltyMultiplier = scenario.customer.yearsWithMHPCO >= 2 ? 0.8 : 1;
    itemPremiumTotal *= loyaltyMultiplier;

    const premium = Math.ceil(itemPremiumTotal + 5);
    results.push({ premium });
  }

  return { results };
}

import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("Quoting", () => {
  it("should compute premium for a single sword (new customer, first policy)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: false },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("should compute premium for other main item types (amulet, staff, potion)", () => {
    const amulet = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "amulet", material: "silver", enchantment: 2, cursed: false },
          ],
        },
      ],
    });
    expect(amulet.results[0]).toEqual({ premium: 71 });

    const staff = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "staff", material: "wood", enchantment: 1, cursed: false },
          ],
        },
      ],
    });
    expect(staff.results[0]).toEqual({ premium: 93 });

    const potion = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "potion", material: "glass", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    expect(potion.results[0]).toEqual({ premium: 49 });
  });
  it("should compute premium for a single component", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "rune", material: "stone", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 33 });
  });
  it("should sum premiums for multiple items", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: false },
            { type: "amulet", material: "silver", enchantment: 2, cursed: false },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 181 });
  });
  it("should apply building block discount for 3 alike components", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "rune", material: "stone", enchantment: 0, cursed: false },
            { type: "rune", material: "stone", enchantment: 0, cursed: false },
            { type: "rune", material: "stone", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("should add 50% surcharge for cursed items", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: true },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 170 });
  });
  it("should add 30% surcharge for enchantment level >= 5", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 5, cursed: false },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 148 });
  });
  it("should apply 20% loyalty discount for customers with >= 2 years", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 3 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: false },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 93 });
  });
  it("should apply 15% discount on subsequent contracts instead of first-insurance surcharge", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: false },
          ],
        },
        {
          op: "quote" as const,
          items: [
            { type: "amulet", material: "silver", enchantment: 2, cursed: false },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
    expect(result.results[1]).toEqual({ premium: 56 });
  });
  it.todo("should round premium in MHPCO's favor (ceiling)");
});

describe("Claims", () => {
  it.todo("should apply 100G deductible and compute payout for a basic claim");
  it.todo("should pay zero when damage is within deductible");
  it.todo("should track remaining payout cap at 2x insurance sum");
  it.todo("should reimburse 50% for items with enchantment >= 8");
  it.todo("should fully reimburse dragon material items");
  it.todo("should reduce remaining cap across multiple claims on same policy");
});

describe("CLI", () => {
  it.todo("should read JSON from stdin and write results to stdout");
});

